// // This module implements a state-space controller with a 4-bit input and output. It has a clock and reset input. The state transitions are as follows:
// - From state 0000, if input is 0, transition to 0001; if input is 1, transition to 0000.
// - From state 0001, if input is 0, transition to 0010; if input is 1, transition to 0001.
// - From state 0010, if input is 0, transition to 0011; if input is 1, transition to 0010.
// - From state 0011, if input is 0, transition to 0000; if input is 1, transition to 0011.
// The output equals the previous state.
module state_space_controller (
    input clk,
    input rst,
    input [3:0] state_input,
    output reg [3:0] control_output
);
    reg [3:0] state;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= 4'b0000;
        end else begin
            case (state)
                4'b0000: state <= (state_input[0]) ? 4'b0001 : 4'b0000;
                4'b0001: state <= (state_input[0]) ? 4'b0010 : 4'b0000;
                4'b0010: state <= (state_input[0]) ? 4'b0011 : 4'b0001;
                4'b0011: state <= (state_input[0]) ? 4'b0000 : 4'b0010;
                default: state <= 4'b0000;
            endcase
        end
    end

    always @(*) begin
        control_output = state;
    end
endmodule

